// // This module implements an 8-bit register with asynchronous clear. The register loads the input data (d) on the negative clock edge when load is low, and clears the register to 1 when the clear signal is low.
module register(
	input clk,
	input clear,
	input load,
	input [7:0] d,
	output reg [7:0] q);always @(posedge clk) begin
		if (clear)
			q <= 8'b00000000;
		else if (load)
			q <= d;
	end

endmodule
